diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 9df08553d86e..f0ba9b03ca45 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -8790,6 +8790,74 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
     }
   }

+  if (match(Op0, m_FPTrunc(m_Value(X)))) {
+    // fcmp pred (fptrunc X), C -> fcmp pred X, C' where C' is computed
+    // from C to preserve the comparison semantics.
+    // For OGE: fcmp oge (fptrunc X), C is true iff X >= threshold
+    // where threshold is the smallest src-type value that truncates to >= C.
+    const APFloat *C;
+    if (match(Op1, m_APFloat(C))) {
+      Type *SrcTy = X->getType()->getScalarType();
+      Type *DstTy = Op1->getType()->getScalarType();
+      
+      // Only handle cases where source type is wider than dest type.
+      if (SrcTy->getFPMantissaWidth() > DstTy->getFPMantissaWidth()) {
+        bool CanFold = false;
+        APFloat Threshold = *C;
+        
+        if (Pred == FCmpInst::FCMP_OGE || Pred == FCmpInst::FCMP_OGT ||
+            Pred == FCmpInst::FCMP_OLE || Pred == FCmpInst::FCMP_OLT) {
+          // Convert C to source type (fpext)
+          bool LosesInfo;
+          APFloat SrcC = *C;
+          SrcC.convert(SrcTy->getFltSemantics(), APFloat::rmNearestTiesToEven, &LosesInfo);
+          
+          // Find the threshold: largest source value that still truncates to C
+          // For OGE: X >= threshold implies fptrunc(X) >= C
+          // Start from SrcC and decrement until truncation changes
+          APFloat TestVal = SrcC;
+          APFloat Truncated = TestVal;
+          Truncated.convert(DstTy->getFltSemantics(), APFloat::rmNearestTiesToEven, &LosesInfo);
+          
+          while (Truncated.compare(*C) == APFloat::cmpEqual) {
+            // Still truncates to C, try smaller
+            APFloat PrevTest = TestVal;
+            if (PrevTest.next(/*nextDown=*/true))
+              break; // Can't go smaller (hit min value)
+            TestVal = PrevTest;
+            Truncated = TestVal;
+            Truncated.convert(DstTy->getFltSemantics(), APFloat::rmNearestTiesToEven, &LosesInfo);
+          }
+          // TestVal now is the smallest value that truncates to C
+          // (or one step below if we went too far)
+          // Actually, we went one step too far. The threshold is PrevTest.
+          // But we need to track it properly.
+          
+          // Let's redo: we want the smallest X such that fptrunc(X) >= C.
+          // If TestVal truncates to < C, then threshold is the next value up.
+          if (Truncated.compare(*C) != APFloat::cmpEqual) {
+            // TestVal truncates to < C, so threshold is the next value
+            if (TestVal.next(/*nextDown=*/false)) {
+              // Can't go up (shouldn't happen), use SrcC
+              Threshold = SrcC;
+            } else {
+              Threshold = TestVal;
+            }
+          } else {
+            // TestVal truncates to C, it's the threshold
+            Threshold = TestVal;
+          }
+          CanFold = true;
+        }
+        
+        if (CanFold) {
+          Constant *NewC = ConstantFP::get(X->getType(), Threshold);
+          return new FCmpInst(Pred, X, NewC, "", &I);
+        }
+      }
+    }
+  }
+
   // Convert a sign-bit test of an FP value into a cast and integer compare.
   // TODO: Simplify if the copysign constant is 0.0 or NaN.
   // TODO: Handle non-zero compare constants.

