{"command": "cat > /tmp/test_threshold.cpp << 'EOF'
#include <iostream>
#include <cmath>
#include <cstdint>

int main() {
    // 100.0 as float
    float f = 100.0f;

    // 100.0 as double
    double d = 100.0;

    // Print the bit representations
    uint32_t fbits;
    uint64_t dbits;
    memcpy(&fbits, &f, 4);
    memcpy(&dbits, &d, 8);

    std::cout << "100.0f bits: " << std::hex << fbits << std::endl;
    std::cout << "100.0d bits: " << std::hex << dbits << std::endl;

    // Find the smallest double that truncates to >= 100.0f
    double test = 100.0;
    while (true) {
        float truncated = (float)test;
        if (truncated < 100.0f) {
            // test is too small, go back up
            // We need the next representable double up
            uint64_t bits;
            memcpy(&bits, &test, 8);
            bits++;
            memcpy(&test, &bits, 8);
            break;
        }
        // Go down one ULP
        uint64_t bits;
        memcpy(&bits, &test, 8);
        bits--;
        memcpy(&test, &bits, 8);
    }

    std::cout << "Threshold double: " << std::scientific << test << std::endl;
    printf("Threshold hex: 0x%016lx\n", *(uint64_t*)&test);
    printf("Truncated to float: %f\n", (float)test);

    return 0;
}
EOF
g++ -o /tmp/test_threshold /tmp/test_threshold.cpp && /tmp/test_threshold"}

